    girl = sys.stdin.readline()
    gl = int(girl.split(' ')[0])
    gr = int(girl.split(' ')[1])

    boy = sys.stdin.readline()
    bl = int(boy.split(' ')[0])
    br = int(boy.split(' ')[1])


def check_possible(g, b):

    if g == b:
        return True

    elif g > b:

        if b == g - 1:
            return True
        else:
            return False

    elif g < b:

        if b <= 2*g + 2:
            return True
        else:
            return False

